create table categorias (ativo boolean not null, ordem_exibicao integer, criado_em timestamp(6) not null, id bigint generated by default as identity, restaurante_id bigint not null, nome varchar(100) not null, descricao TEXT, primary key (id));
create table clientes (ativo boolean not null, data_nascimento date, atualizado_em timestamp(6), criado_em timestamp(6) not null, id bigint generated by default as identity, cpf varchar(14) unique, telefone varchar(20) not null unique, email varchar(255) unique, nome_completo varchar(255) not null, primary key (id));
create table cupons (ativo boolean not null, desconto_maximo numeric(10,2), limite_uso integer, quantidade_usada integer not null, valor_desconto numeric(10,2) not null, valor_minimo_pedido numeric(10,2), criado_em timestamp(6) not null, id bigint generated by default as identity, valido_ate timestamp(6) not null, valido_de timestamp(6) not null, tipo_desconto varchar(20) not null check (tipo_desconto in ('PERCENTUAL','VALOR_FIXO')), codigo varchar(50) not null unique, descricao TEXT, primary key (id));
create table cupons_pedido (desconto_aplicado numeric(10,2) not null, cupom_id bigint not null, id bigint generated by default as identity, pedido_id bigint not null, primary key (id));
create table documentos_entregador (data_validade date, verificado boolean not null, criado_em timestamp(6) not null, entregador_id bigint not null, id bigint generated by default as identity, verificado_em timestamp(6), verificado_por uuid, tipo_documento varchar(50) not null check (tipo_documento in ('CNH','RG','CPF','COMPROVANTE_RESIDENCIA','FOTO_VEICULO','CRLV')), numero_documento varchar(100), url_arquivo varchar(500) not null, primary key (id));
create table enderecos_cliente (estado varchar(2) not null, latitude numeric(10,8), longitude numeric(11,8), padrao boolean not null, atualizado_em timestamp(6), cliente_id bigint not null, criado_em timestamp(6) not null, id bigint generated by default as identity, cep varchar(10) not null, numero varchar(20) not null, rotulo varchar(50), bairro varchar(100) not null, cidade varchar(100) not null, complemento varchar(255), logradouro varchar(255) not null, primary key (id));
create table enderecos_restaurante (estado varchar(2) not null, latitude numeric(10,8), longitude numeric(11,8), id bigint generated by default as identity, restaurante_id bigint not null unique, cep varchar(10) not null, numero varchar(20) not null, bairro varchar(100) not null, cidade varchar(100) not null, complemento varchar(255), logradouro varchar(255) not null, primary key (id));
create table entregador_restaurante (ativo boolean not null, desvinculado_em timestamp(6), entregador_id bigint not null, id bigint generated by default as identity, restaurante_id bigint not null, vinculado_em timestamp(6) not null, primary key (id), unique (entregador_id, restaurante_id));
create table entregadores (ativo boolean not null, avaliacao numeric(3,2), disponivel boolean not null, total_entregas integer not null, categoria_cnh varchar(5) check (categoria_cnh in ('A','B','AB','C','D','E')), atualizado_em timestamp(6), criado_em timestamp(6) not null, id bigint generated by default as identity, placa_veiculo varchar(10), cpf varchar(14) not null unique, cnh varchar(20) unique, telefone varchar(20) not null unique, tipo_veiculo varchar(30) check (tipo_veiculo in ('BICICLETA','MOTO','CARRO')), cor_veiculo varchar(50), modelo_veiculo varchar(100), foto_cnh_url varchar(500), foto_perfil_url varchar(500), foto_veiculo_url varchar(500), email varchar(255) unique, nome_completo varchar(255) not null, primary key (id));
create table grupos_opcoes (maximo_selecoes integer, minimo_selecoes integer, obrigatorio boolean not null, ordem_exibicao integer, id bigint generated by default as identity, produto_id bigint not null, nome varchar(100) not null, descricao TEXT, primary key (id));
create table historico_disponibilidade_entregador (disponivel boolean not null, latitude numeric(10,8), longitude numeric(11,8), criado_em timestamp(6) not null, entregador_id bigint not null, id bigint generated by default as identity, primary key (id));
create table historico_status_pedido (criado_em timestamp(6) not null, id bigint generated by default as identity, pedido_id bigint not null, status varchar(30) not null check (status in ('AGUARDANDO_CONFIRMACAO','PENDENTE','CONFIRMADO','EM_PREPARO','PREPARANDO','PRONTO','EM_ENTREGA','DESPACHADO','ENTREGUE','CANCELADO')), criado_por varchar(100), observacoes TEXT, primary key (id));
create table horarios_restaurante (dia_semana integer not null, fechado boolean not null, horario_abertura time(6) not null, horario_fechamento time(6) not null, id bigint generated by default as identity, restaurante_id bigint not null, primary key (id));
create table imagens_produto (altura integer, largura integer, ordem_exibicao integer, principal boolean not null, atualizado_em timestamp(6), criado_em timestamp(6) not null, id bigint generated by default as identity, produto_id bigint not null, tamanho_bytes bigint not null, tipo_mime varchar(100) not null, url_bucket varchar(500), imagem_base64 TEXT, nome_arquivo varchar(255) not null, primary key (id));
