create table pedidos (desconto numeric(10,2), subtotal numeric(10,2) not null, taxa_entrega numeric(10,2), valor_total numeric(10,2), valor_troco numeric(10,2), cancelado_em timestamp(6), cliente_id bigint not null, confirmado_em timestamp(6), criado_em timestamp(6) not null, data_atualizacao timestamp(6), data_pedido timestamp(6) not null, despachado_em timestamp(6), endereco_entrega_id bigint not null, entregador_id bigint, entregue_em timestamp(6), id bigint generated by default as identity, preparando_em timestamp(6), previsao_entrega timestamp(6), pronto_em timestamp(6), restaurante_id bigint, tipo_pagamento_id bigint not null, status varchar(50) not null check (status in ('AGUARDANDO_CONFIRMACAO','PENDENTE','CONFIRMADO','EM_PREPARO','PREPARANDO','PRONTO','EM_ENTREGA','DESPACHADO','ENTREGUE','CANCELADO')), status_pagamento varchar(50) not null check (status_pagamento in ('PENDENTE','PROCESSANDO','APROVADO','RECUSADO','CANCELADO','ESTORNADO')), cliente_nome varchar(255), motivo_cancelamento TEXT, numero_pedido varchar(255) not null unique, observacoes TEXT, primary key (id));
create table produtos (destaque boolean not null, disponivel boolean not null, ordem_exibicao integer, preco numeric(10,2) not null, preco_promocional numeric(10,2), tempo_preparo integer, atualizado_em timestamp(6), categoria_id bigint not null, criado_em timestamp(6) not null, id bigint generated by default as identity, restaurante_id bigint not null, descricao TEXT, nome varchar(255) not null, primary key (id));
create table restaurante_tipo_pagamento (ativo boolean not null, ordem_exibicao integer, id bigint generated by default as identity, restaurante_id bigint not null, tipo_pagamento_id bigint not null, vinculado_em timestamp(6) not null, primary key (id), unique (restaurante_id, tipo_pagamento_id));
