create table enderecos_cliente (estado varchar(2) not null, latitude numeric(10,8), longitude numeric(11,8), padrao boolean not null, atualizado_em timestamp(6), cliente_id bigint not null, criado_em timestamp(6) not null, id bigint generated by default as identity, cep varchar(10) not null, numero varchar(20) not null, rotulo varchar(50), bairro varchar(100) not null, cidade varchar(100) not null, complemento varchar(255), logradouro varchar(255) not null, primary key (id));
create table enderecos_restaurante (estado varchar(2) not null, latitude numeric(10,8), longitude numeric(11,8), id bigint generated by default as identity, restaurante_id bigint not null unique, cep varchar(10) not null, numero varchar(20) not null, bairro varchar(100) not null, cidade varchar(100) not null, complemento varchar(255), logradouro varchar(255) not null, primary key (id));
