create table entregadores (ativo boolean not null, avaliacao numeric(3,2), disponivel boolean not null, total_entregas integer not null, categoria_cnh varchar(5) check (categoria_cnh in ('A','B','AB','C','D','E')), atualizado_em timestamp(6), criado_em timestamp(6) not null, id bigint generated by default as identity, placa_veiculo varchar(10), cpf varchar(14) not null unique, cnh varchar(20) unique, telefone varchar(20) not null unique, tipo_veiculo varchar(30) check (tipo_veiculo in ('BICICLETA','MOTO','CARRO')), cor_veiculo varchar(50), modelo_veiculo varchar(100), foto_cnh_url varchar(500), foto_perfil_url varchar(500), foto_veiculo_url varchar(500), email varchar(255) unique, nome_completo varchar(255) not null, primary key (id));
